    public boolean updateEntityDataSource(DataEntityRuntimeContext _entityCtx, DataEntityDataSourceRuntimeContext _dataSourceCtx)
    {
        boolean ret;

        switch (_dataSourceCtx.name())
        {
            case dataEntityDataSourceStr(FinancialDimensionValueLegalEntityOverrideEntity, DimensionAttrValueLedgerOverride):

                DimensionAttrValueLedgerOverride override = _dataSourceCtx.getBuffer();
                UBSInventSiteCrossCompany UBSInventSiteCrossCompany = UBSInventSiteCrossCompany::find(this.SiteId, this.LegalEntityId);
                if(this.SiteId && !UBSInventSiteCrossCompany)
                {
                    throw error(strFmt("@UBS:UBSSiteIdDoesNotExist", this.SiteId, this.LegalEntityId));
                }

                override.UBSInventSiteCCRecId = UBSInventSiteCrossCompany.RecId;
                break;
        }

        ret = next updateEntityDataSource(_entityCtx,_dataSourceCtx);
        
        return ret;
    }

