    public void postLoad()
    {
        UBSInventSiteCrossCompany inventSiteCC;
        next postLoad();

        if(this.UBSInventSiteCCRecId)
        {
            inventSiteCC = UBSInventSiteCrossCompany::findByRecId(this.UBSInventSiteCCRecId);
            this.SiteId = inventSiteCC.SiteId;
        }
    }
